// ============ SCROLL REVEAL ============
const revealEls = document.querySelectorAll(
  ".reveal,.reveal-l,.reveal-r,.reveal-card",
);
const revObs = new IntersectionObserver(
  (entries) => {
    entries.forEach((e) => {
      if (e.isIntersecting) {
        e.target.classList.add("visible");
        // Animate service bars
        const bar = e.target.querySelector(".srv-bar-fill");
        if (bar)
          setTimeout(() => {
            bar.style.width = bar.dataset.w + "%";
          }, 300);
        // Also find bars in children
        e.target.querySelectorAll(".srv-bar-fill").forEach((b) => {
          setTimeout(() => {
            b.style.width = b.dataset.w + "%";
          }, 300);
        });
      }
    });
  },
  { threshold: 0.1 },
);
revealEls.forEach((el) => revObs.observe(el));

