// ============ SVG MAP RENDERING ============
let visibleCodes = new Set(AIRPORTS.map((a) => a[0]));

function getTypeColor(type) {
  return type === "both" ? "#4a9eff" : "#aec9f5";
}

function renderMap() {
  const svg = document.getElementById("airport-dots");
  svg.innerHTML = "";
  const tooltip = document.getElementById("map-tooltip");

  AIRPORTS.forEach(([code, city, country, region, x, y, type, home]) => {
    const vis = visibleCodes.has(code);
    const g = document.createElementNS("http://www.w3.org/2000/svg", "g");
    g.setAttribute("class", home ? "ap-dot home-dot" : "ap-dot");
    g.style.opacity = vis ? "1" : "0.08";
    g.style.transition = "opacity .4s";

    const outerR = home ? 14 : 6;
    const innerR = home ? 8 : 4;
    const col = home ? "#c0394f" : getTypeColor(type);

    // Pulse ring for home airports
    if (home) {
      const ring = document.createElementNS(
        "http://www.w3.org/2000/svg",
        "circle",
      );
      ring.setAttribute("cx", x);
      ring.setAttribute("cy", y);
      ring.setAttribute("r", outerR);
      ring.setAttribute("fill", "none");
      ring.setAttribute("stroke", "rgba(192,57,79,0.35)");
      ring.setAttribute("stroke-width", "1.5");
      g.appendChild(ring);
    }

    const dot = document.createElementNS(
      "http://www.w3.org/2000/svg",
      "circle",
    );
    dot.setAttribute("cx", x);
    dot.setAttribute("cy", y);
    dot.setAttribute("r", innerR);
    dot.setAttribute("fill", col);
    g.appendChild(dot);

    // Label
    const lbl = document.createElementNS("http://www.w3.org/2000/svg", "text");
    lbl.setAttribute("x", x + (home ? 12 : 8));
    lbl.setAttribute("y", y - (home ? 4 : 2));
    lbl.setAttribute("class", "ap-code");
    lbl.setAttribute("font-family", "DM Mono,monospace");
    lbl.setAttribute("font-size", home ? "11" : "8.5");
    lbl.setAttribute("fill", "#fff");
    lbl.setAttribute("font-weight", home ? "600" : "500");
    lbl.setAttribute("opacity", "0.9");
    lbl.textContent = code;
    g.appendChild(lbl);

    // Tooltip interaction
    g.style.cursor = "pointer";
    g.addEventListener("mouseenter", (e) => {
      document.getElementById("tt-code").textContent = code;
      document.getElementById("tt-city").textContent = city;
      document.getElementById("tt-country").textContent =
        country +
        (type === "both"
          ? " · Air & Sea"
          : type === "air"
            ? " · Air Freight"
            : " · Sea Freight");
      document.getElementById("tt-region").innerHTML =
        `<i class="fa-solid fa-location-dot" aria-hidden="true"></i> ${region}`;
      const homeTag = document.getElementById("tt-home");
      homeTag.style.display = home ? "block" : "none";
      const rect = document.getElementById("world-svg").getBoundingClientRect();
      const mapContainer = document.querySelector(".map-container");
      const mcRect = mapContainer.getBoundingClientRect();
      // Position tooltip near dot
      const svgEl = document.getElementById("world-svg");
      const vb = svgEl.viewBox.baseVal;
      const scaleX = svgEl.clientWidth / vb.width;
      const scaleY = svgEl.clientHeight / vb.height;
      let tx = x * scaleX + 12;
      let ty = y * scaleY - 20;
      if (tx + 200 > mcRect.width) tx = x * scaleX - 200;
      tooltip.style.left = tx + "px";
      tooltip.style.top = ty + "px";
      tooltip.classList.add("show");
    });
    g.addEventListener("mouseleave", () => tooltip.classList.remove("show"));

    svg.appendChild(g);
  });
}

// ============ AIRPORT LIST RENDERING ============
function renderList() {
  const grid = document.getElementById("al-grid");
  grid.innerHTML = "";
  let count = 0;
  AIRPORTS.forEach(([code, city, country, region, x, y, type, home]) => {
    const vis = visibleCodes.has(code);
    const div = document.createElement("div");
    div.className =
      "al-item" + (vis ? "" : " hidden") + (home ? " highlighted" : "");
    div.dataset.code = code;
    div.dataset.city = city.toLowerCase();
    div.dataset.country = country.toLowerCase();
    div.dataset.region = region;
    div.dataset.type = type;
    div.innerHTML = `
      <div class="al-code">${code}</div>
      <div class="al-city">${city}</div>
      <div class="al-country">${country}</div>
      ${home ? '<div class="al-home-tag"><i class="fa-solid fa-plane" aria-hidden="true"></i> Origin Hub</div>' : ""}
    `;
    div.addEventListener("click", () => {
      // Highlight on map
      document
        .querySelectorAll(".al-item")
        .forEach((i) => (i.style.background = ""));
      div.style.background = "rgba(123,28,46,0.3)";

      // Redirect to Google Maps with airport search
      const searchQuery = `${city} ${code} airport`;
      const mapsUrl = `https://www.google.com/maps/search/${encodeURIComponent(searchQuery)}`;
      window.open(mapsUrl, "_blank", "noopener");
    });
    if (vis) count++;
    grid.appendChild(div);
  });
  document.getElementById("al-count").textContent = "140+ airports";
  document.getElementById("result-count").textContent = "140+";
}

// ============ FILTER LOGIC ============
function applyFilters() {
  const search = document
    .getElementById("search-input")
    .value.toLowerCase()
    .trim();
  const region = document.getElementById("region-select").value;
  const type = document.getElementById("type-select").value;

  visibleCodes = new Set();
  AIRPORTS.forEach(([code, city, country, airRegion, x, y, airType, home]) => {
    const matchSearch =
      !search ||
      code.toLowerCase().includes(search) ||
      city.toLowerCase().includes(search) ||
      country.toLowerCase().includes(search);
    const matchRegion = region === "all" || airRegion === region;
    const matchType =
      type === "all" ||
      (type === "air" && (airType === "air" || airType === "both")) ||
      (type === "sea" && airType === "both") ||
      (type === "both" && airType === "both");
    if (matchSearch && matchRegion && matchType) {
      visibleCodes.add(code);
    }
  });

  renderMap();
  renderList();
}

function clearFilters() {
  document.getElementById("search-input").value = "";
  document.getElementById("region-select").value = "all";
  document.getElementById("type-select").value = "all";
  visibleCodes = new Set(AIRPORTS.map((a) => a[0]));
  renderMap();
  renderList();
}

// Live search on input
document.getElementById("search-input").addEventListener("input", applyFilters);
document
  .getElementById("region-select")
  .addEventListener("change", applyFilters);
document.getElementById("type-select").addEventListener("change", applyFilters);

// ============ AWB TRACKING =========
let awbCarriers = null;
let awbLoadPromise = null;

const popularRow = document.querySelector(".airlines-row");
if (popularRow) popularRow.remove();

function normalizeAwbInput(value) {
  return String(value || "").replace(/\D/g, "");
}

function setTrackMessage(text, tone) {
  const el = document.getElementById("track-message");
  if (!el) return;
  if (!text) {
    el.textContent = "";
    el.className = "track-message";
    return;
  }
  el.textContent = text;
  el.className = tone ? `track-message is-${tone}` : "track-message";
}

async function loadAwbCarriers() {
  if (awbCarriers) return awbCarriers;
  if (!awbLoadPromise) {
    awbLoadPromise = fetch("/air_cargo_tracker.json", { cache: "no-store" })
      .then((res) => (res.ok ? res.json() : []))
      .catch(() => [])
      .then((data) => {
        awbCarriers = Array.isArray(data) ? data : [];
        return awbCarriers;
      });
  }
  return awbLoadPromise;
}

function findCarrierByPrefix(prefix) {
  if (!awbCarriers || !prefix) return null;
  return awbCarriers.find(
    (item) =>
      Array.isArray(item.prefix) && item.prefix.includes(prefix) && item.url,
  );
}

async function trackDirect() {
  const input = document.getElementById("awb-input");
  if (!input) return;
  const awbDigits = normalizeAwbInput(input.value);
  if (!awbDigits) {
    setTrackMessage("Enter an AWB number to track.", "error");
    input.focus();
    return;
  }
  if (awbDigits.length < 3) {
    setTrackMessage("Enter at least the 3-digit prefix.", "error");
    input.focus();
    return;
  }

  setTrackMessage("Checking carrier...");
  await loadAwbCarriers();
  const prefix = awbDigits.slice(0, 3);
  const carrier = findCarrierByPrefix(prefix);

  if (carrier && carrier.url) {
    setTrackMessage(`Matched prefix ${prefix}. Redirecting...`, "success");
    window.open(carrier.url, "_blank", "noopener");
  } else {
    setTrackMessage(`No carrier found for prefix ${prefix}.`, "warning");
  }
}

async function trackOptions() {
  const input = document.getElementById("awb-input");
  if (!input) return;
  const awbDigits = normalizeAwbInput(input.value);
  if (!awbDigits) {
    setTrackMessage("Enter an AWB number to see options.", "error");
    input.focus();
    return;
  }
  if (awbDigits.length < 3) {
    setTrackMessage("Enter at least the 3-digit prefix.", "error");
    input.focus();
    return;
  }

  await loadAwbCarriers();
  const prefix = awbDigits.slice(0, 3);
  const carrier = findCarrierByPrefix(prefix);

  if (carrier && carrier.url) {
    setTrackMessage(
      `Matched prefix ${prefix}. Opening carrier site.`,
      "success",
    );
    window.open(carrier.url, "_blank", "noopener");
  } else {
    setTrackMessage(`No carrier found for prefix ${prefix}.`, "warning");
  }
}

function wireTracking() {
  const input = document.getElementById("awb-input");
  if (!input) return;
  input.addEventListener("keydown", (event) => {
    if (event.key === "Enter") {
      event.preventDefault();
      trackDirect();
    }
  });
  loadAwbCarriers();
  window.trackDirect = trackDirect;
  window.trackOptions = trackOptions;
}

// ============ FORM SUBMIT ============
function submitQuote(btn) {
  btn.innerHTML =
    '<i class="fa-solid fa-spinner fa-spin" aria-hidden="true"></i> Sending...';
  btn.style.background = "#666";
  setTimeout(() => {
    btn.innerHTML =
      '<i class="fa-solid fa-check" aria-hidden="true"></i> Enquiry Sent - We\'ll respond within 2 hours';
    btn.style.background = "#1a7a3c";
    btn.style.fontSize = "13px";
    setTimeout(() => {
      btn.innerHTML =
        'Send Enquiry <i class="fa-solid fa-arrow-right" aria-hidden="true"></i>';
      btn.style.background = "";
      btn.style.fontSize = "";
    }, 5000);
  }, 1500);
}

